#include <stdio.h>
#define DIM 5

int main() {
    int i;
    long int proizvod = 1;
    int matrica[DIM][DIM] = {
        {1, 2, 3, 4, 5},
        {6, 7, 8, 9, 6},
        {8, 7, 6, 5, 11},
        {3, 2, 1, 1, 4},
        {7, 8, 3, 2, 2}
    };

    for(i = 0; i < DIM; i++){
        proizvod *= matrica[i][i]; /* elementi sa glavne dijagonale */
        proizvod *= matrica[i][DIM-1-i]; /* elementi sa sporedne dijagonale */
    }
    
    proizvod /= matrica[DIM/2][DIM/2];
    printf("Proizvod elemenata na glavnoj i sporednoj dijagonali je %ld", proizvod);

    return 0;
}
